-- ============================================================================
-- 05-add-cities.sql — add new catalogue cities (Vienna + SE Asia) and countries.
-- Run in Supabase -> SQL Editor (same place as the seed). Idempotent (upsert).
-- Run AFTER 03-catalogue.sql + 04-seed-catalogue.sql. No service_role key needed.
-- ============================================================================

insert into public.countries (code, name, iso2, currency, visa, best_time, safety, extras) values
  ('Austria', 'Austria', 'AT', 'EUR', 'EU freedom of movement: Hungarian/EU citizens need no visa and no ETIAS for any length of stay. Enter and reside freely with a valid passport or national ID card.', 'May-September for warm weather and Alpine hiking; December-March for ski season. Spring and early autumn offer mild weather and fewer crowds.', 'Very safe. Low violent crime; main risk is petty theft/pickpocketing in tourist areas of Vienna and Salzburg. Excellent healthcare and infrastructure.', '{}'::jsonb),
  ('Philippines', 'Philippines', 'PH', 'PHP', 'Visa-free for up to 30 days for Hungarian/EU passport holders. Passport must be valid at least 6 months beyond stay; onward/return ticket may be requested. Extensions available locally via the Bureau of Immigration.', 'December-April (dry season) is ideal, especially January-March. Avoid June-October typhoon and rainy season; February-April best for beaches and diving.', 'Generally safe in tourist areas (Cebu, Palawan, Boracay, Manila tourist zones). Petty theft and scams occur in cities. Avoid the Sulu Archipelago and parts of western/central Mindanao due to insurgency and kidnapping risk. Watch sea conditions during typhoon season.', '{}'::jsonb)
on conflict (code) do update set
  name=excluded.name, iso2=excluded.iso2, currency=excluded.currency,
  visa=excluded.visa, best_time=excluded.best_time, safety=excluded.safety, updated_at=now();

insert into public.cities (country, city, region, region_name, lat, lng, daily_living_mid, accom_mid, rent_monthly, attributes) values
  ('Austria', 'Vienna', 'EU', 'Europe', 48.2082, 16.3738, 130, 140, 1450, '{"costs":{"allInDayMid":[95,180],"accomPerNight":{"budget":75,"mid":140,"nice":260},"rentMonthly":1450,"dailyLiving":{"low":65,"mid":130,"high":230}},"food":"Sausage at a Würstelstand ~€4-5; daily lunch menu (Mittagsmenü) ~€12-15/person; casual dinner for 2 with drinks ~€55-70; mid-range Wiener Schnitzel dinner for 2 ~€90-110; local beer (0.5L) ~€4.50; melange coffee in a classic café ~€4.50.","transport":"Excellent Wiener Linien metro/tram/bus network: single ride €2.60, 24h pass €8, 72h pass €17.10; the 365-day annual pass is famously €365. Bolt/Uber widely available, short city ride ~€9-14. Mostly walkable and very bike-friendly.","internet":"Austria/EU eSIM cheap: ~$4-10 for 5-10GB (Airalo/Saily); local SACK/Hot Tariff SIMs offer big data bundles. Fast, reliable fiber everywhere. Coworking: Impact Hub day pass ~€20, monthly from ~€75; Zoku day pass ~€38; premium hot-desk memberships ~€125-240/month.","landmarks":[{"name":"Schönbrunn Palace & Gardens","why":"Former Habsburg summer residence with vast baroque gardens, Gloriette and the world''s oldest zoo","when":"Early morning to beat crowds; gardens free to roam","how":"U4 metro to Schönbrunn, ~15 min from centre","cost":"Gardens free; palace tour ~€27","time":"Half day"},{"name":"St. Stephen''s Cathedral (Stephansdom)","why":"Gothic landmark in the heart of the old town with a tiled roof and tower climb over the city","when":"Anytime; climb the south tower for views","how":"U1/U3 Stephansplatz, dead centre","cost":"Nave free; tower/catacombs ~€6-7","time":"1-2 hours"},{"name":"Belvedere Palace (Klimt''s The Kiss)","why":"Baroque palace housing Gustav Klimt''s The Kiss and Austrian art, with terraced gardens","when":"Weekday mornings","how":"Tram D or short walk from centre","cost":"~€17 upper Belvedere","time":"2-3 hours"},{"name":"Naschmarkt & MuseumsQuartier","why":"Lively food market for cheap eats, plus a cultural courtyard of museums and cafés to work/relax","when":"Naschmarkt mornings (closed Sundays); MQ courtyard evenings","how":"U4 Kettenbrückengasse / U2 MuseumsQuartier","cost":"Free to wander","time":"2-3 hours"}],"weather":{"hazard":"Best months May-Jun and Sep-Oct (mild, sunny, fewer crowds). Jul-Aug warm and the wettest (thunderstorms); winters cold, grey and damp with occasional snow Dec-Feb. No monsoon/typhoon risk.","months":[{"m":"Jan","hi":3,"lo":-3,"rain":40},{"m":"Feb","hi":6,"lo":-2,"rain":40},{"m":"Mar","hi":11,"lo":1,"rain":50},{"m":"Apr","hi":16,"lo":5,"rain":45},{"m":"May","hi":21,"lo":10,"rain":75},{"m":"Jun","hi":24,"lo":14,"rain":70},{"m":"Jul","hi":27,"lo":15,"rain":80},{"m":"Aug","hi":26,"lo":15,"rain":70},{"m":"Sep","hi":21,"lo":11,"rain":65},{"m":"Oct","hi":15,"lo":6,"rain":45},{"m":"Nov","hi":9,"lo":2,"rain":45},{"m":"Dec","hi":4,"lo":-2,"rain":45}]}}'::jsonb),
  ('Thailand', 'Phuket', 'SE', 'Southeast Asia', 7.8804, 98.3923, 70, 50, 690, '{"costs":{"allInDayMid":[55,95],"accomPerNight":{"budget":22,"mid":50,"nice":120},"rentMonthly":690,"dailyLiving":{"low":40,"mid":70,"high":120}},"food":"Street/market Thai meal $2-4 (60-120 THB); casual sit-down dinner for 2 ~$16-22; mid-range Western/seafood dinner for 2 ~$45-60; local Chang/Leo beer $2-4 at a shop, $3-5 in a bar; Western cafe coffee $2.50-4.50 (90-160 THB).","transport":"No real public transit beyond slow songthaews (~$1/30 THB). Grab/Bolt is the nomad default: short hop $3-5, airport to Patong ~$20-25. Tuk-tuks are tourist-priced ($10-18 even short) - avoid or haggle hard. Most renters get a scooter: $90-150/month plus ~$5 to fill the tank.","internet":"Fibre in condos is fast and cheap (often bundled in rent, otherwise ~$15-20/mo). Tourist eSIM/SIM: Airalo 10GB ~$11/30 days, or local AIS/True tourist SIM 299-599 THB ($9-18) with generous data. Coworking is plentiful (Bangtao, Rawai, Chalong): day pass 150-400 THB ($4-11), monthly hot desk ~$80-150.","landmarks":[{"name":"Big Buddha (Phra Phutthamingmongkhon)","why":"45m marble-clad hilltop Buddha with 360-degree island and coastline views; one of Phuket''s signature sights.","when":"Early morning to beat heat and crowds; clear dry-season days for views.","how":"20-30 min by Grab/scooter from Phuket Town or Chalong up a winding hill road.","cost":"Free (donation welcomed)","time":"1-1.5 hrs"},{"name":"Phuket Old Town (Thalang Road)","why":"Sino-Portuguese shophouse streets with cafes, street art, galleries and a lively Sunday Walking Street night market - the most workable, atmospheric base for nomads.","when":"Late afternoon into evening; Sunday for the walking-street market.","how":"Central; walkable, or short Grab ride from anywhere in the city.","cost":"Free to wander","time":"2-3 hrs"},{"name":"Phi Phi Islands day trip","why":"Iconic limestone cliffs, Maya Bay and snorkelling lagoons - the classic Andaman boat excursion.","when":"Dry season Nov-Apr for calm seas; book early-departure speedboat tours.","how":"Speedboat/ferry from Rassada Pier; most book a guided day tour with hotel pickup.","cost":"$35-55 pp tour incl. lunch + national park fee","time":"Full day"},{"name":"Kata & Karon Beaches","why":"Long, swimmable west-coast sand beaches with sunset bars and surf - the relaxed counterpoint to busy Patong.","when":"Dry season for swimming; rainy-season swells suit surfers.","how":"15-25 min by Grab or scooter from Phuket Town.","cost":"Free (sun-lounger ~100-200 THB)","time":"Half day"}],"weather":{"hazard":"Best months Dec-Mar (dry, calm seas, lower humidity). Southwest monsoon May-Oct brings heavy rain, big swells and frequent red-flag/rip-current beach closures - Sep-Oct wettest. Hot and humid year-round (highs 31-34C).","months":[{"m":"Jan","hi":32.7,"lo":22.7,"rain":35},{"m":"Feb","hi":33.9,"lo":22.9,"rain":40},{"m":"Mar","hi":34.3,"lo":23.5,"rain":75},{"m":"Apr","hi":34,"lo":24.1,"rain":125},{"m":"May","hi":32.8,"lo":24.3,"rain":295},{"m":"Jun","hi":32.3,"lo":24.2,"rain":265},{"m":"Jul","hi":31.9,"lo":24.3,"rain":215},{"m":"Aug","hi":31.6,"lo":24.3,"rain":245},{"m":"Sep","hi":31.4,"lo":23.8,"rain":325},{"m":"Oct","hi":31.5,"lo":23.5,"rain":315},{"m":"Nov","hi":32,"lo":23.3,"rain":195},{"m":"Dec","hi":31.9,"lo":22.9,"rain":80}]}}'::jsonb),
  ('Thailand', 'Krabi', 'SE', 'Southeast Asia', 8.0863, 98.9063, 55, 42, 480, '{"costs":{"allInDayMid":[40,75],"accomPerNight":{"budget":18,"mid":42,"nice":95},"rentMonthly":480,"dailyLiving":{"low":30,"mid":55,"high":95}},"food":"Street pad thai or khao gaeng 40-70 THB ($1.20-2); casual Thai dinner for two 250-400 THB ($7-12); mid-range Western/seafood dinner for two with drinks 700-1,200 THB ($20-35); local beer 70-90 THB ($2-2.60); coffee 60-80 THB ($1.80-2.40).","transport":"No mass transit; songthaew shared trucks 30-60 THB per ride. Scooter rental 200-300 THB/day ($6-9) is the nomad norm. Grab works in Krabi Town/Ao Nang: short hop 80-150 THB, airport to Ao Nang ~500-600 THB ($15-18). Longtail boat to Railay ~150-200 THB pp.","internet":"Tourist eSIM (AIS/TrueMove) ~$8-15 for 15-30GB. Fiber in condos is reliable (50-200 Mbps). Few dedicated coworking spaces; cafes in Ao Nang and Krabi Town serve as workspots, plus a handful of small coworking/coliving options around 150-250 THB/day.","landmarks":[{"name":"Railay Beach","why":"Iconic limestone-cliff peninsula reachable only by boat, with world-class rock climbing and turquoise swimming bays.","when":"Dry season Dec-Mar, mornings before crowds","how":"Longtail boat from Ao Nang (~150-200 THB pp, 15 min)","cost":"Boat ~$5 pp round trip; beach free","time":"Half to full day"},{"name":"Four Islands / Phi Phi island-hopping tour","why":"Snorkeling and beach-hopping among Krabi''s famous karst islands (Chicken, Tup, Poda, Phi Phi).","when":"Dry season for calm seas; book early for morning departure","how":"Longtail or speedboat day tour from Ao Nang pier","cost":"$25-45 pp incl. lunch and gear","time":"Full day"},{"name":"Tiger Cave Temple (Wat Tham Suea)","why":"1,260-step climb to a clifftop Buddha with panoramic views over Krabi''s jungle and karst landscape.","when":"Early morning to beat the heat","how":"Scooter or Grab ~9 km from Krabi Town","cost":"Free (donation)","time":"2-3 hours"},{"name":"Emerald Pool & Hot Springs (Khlong Thom)","why":"Spring-fed jade pools and natural warm waterfalls in the Thung Teao forest reserve.","when":"Dry season; weekdays are quieter","how":"Scooter or day tour ~1 hr from Ao Nang","cost":"~200 THB ($6) entry pp","time":"Half day"}],"weather":{"hazard":"Best months Dec-Mar (dry, calm seas). Southwest monsoon May-Oct brings heavy rain and rough seas; Sep-Oct wettest (~280-300mm/mo) with some island tours cancelled. Hot and humid year-round; no typhoons but monsoon downpours and high humidity.","months":[{"m":"Jan","hi":32,"lo":22,"rain":33},{"m":"Feb","hi":34,"lo":22,"rain":23},{"m":"Mar","hi":34,"lo":23,"rain":61},{"m":"Apr","hi":34,"lo":24,"rain":114},{"m":"May","hi":32,"lo":24,"rain":203},{"m":"Jun","hi":31,"lo":24,"rain":203},{"m":"Jul","hi":31,"lo":24,"rain":208},{"m":"Aug","hi":31,"lo":24,"rain":241},{"m":"Sep","hi":31,"lo":24,"rain":302},{"m":"Oct","hi":31,"lo":23,"rain":279},{"m":"Nov","hi":31,"lo":23,"rain":195},{"m":"Dec","hi":31,"lo":23,"rain":97}]}}'::jsonb),
  ('Thailand', 'Koh Samui', 'SE', 'Southeast Asia', 9.512, 100.014, 65, 55, 700, '{"costs":{"allInDayMid":[45,90],"accomPerNight":{"budget":22,"mid":55,"nice":130},"rentMonthly":700,"dailyLiving":{"low":35,"mid":65,"high":110}},"food":"Local Thai dish at a market or roadside spot ~$3 (100 THB); casual sit-down meal for 2 ~$16-22; mid-range dinner for 2 with drinks ~$40-55; big Chang/Leo beer ~$2.50-3.50; coffee at a cafe ~$2.50-3.50. Western/tourist restaurants in Chaweng run notably higher.","transport":"No public buses to speak of; scooter rental is the norm at ~$120-170/month (4,000-6,000 THB) plus cheap fuel. Songthaew shared trucks ~$1.50-3 per ride. Grab and Bolt ride-hail work island-wide: short hop ~$3-5, Chaweng to the airport ~$5-8. Taxis are pricey and often metered loosely, so ride-hail apps are better value.","internet":"Tourist eSIM (e.g. Airalo/Holafly) ~$4-15 for 5-20GB; local AIS/TrueMove monthly SIM ~$15-25 for big data. 4G/5G is solid around Chaweng, Lamai, Bophut and the ring road; weaker on the mountainous interior and far western beaches. Coworking at Mantra Work Lounge ~$17/day (600 THB), ~$100/week, ~$340/month (12,000 THB); other spaces in Maenam/Fisherman''s Village similar.","landmarks":[{"name":"Big Buddha (Wat Phra Yai)","why":"Iconic 12m golden seated Buddha on Koh Faan islet, the island''s most recognizable landmark with sea views and a small temple market","when":"Early morning or late afternoon to avoid midday heat and tour crowds","how":"Northeast coast near the airport; 15-20 min scooter or Grab from Chaweng","cost":"Free (donations welcome)","time":"1 hour"},{"name":"Ang Thong National Marine Park","why":"42-island archipelago of limestone karsts, hidden lagoons and snorkeling; the standout day trip from Samui","when":"Dry season Jan-Apr for calm seas; boat tours often pause in heavy Nov rains","how":"Full-day speedboat or big-boat tour from Nathon/Bophut piers","cost":"Tour ~$45-65/person incl. park fee, lunch, kayak","time":"Full day"},{"name":"Fisherman''s Village, Bophut","why":"Restored old-town lane of wooden Sino-Portuguese shophouses with restaurants, bars and the Friday Walking Street night market","when":"Friday evening for the walking street; any evening for dining","how":"North coast; 15 min scooter or Grab from Chaweng","cost":"Free to wander; street food from ~$2","time":"2-3 hours"},{"name":"Na Muang Waterfalls & viewpoints","why":"Twin jungle waterfalls with a swimmable lower pool, plus the Lamai coast''s Hin Ta & Hin Yai (Grandfather/Grandmother) rocks nearby","when":"Rainy season (Sep-Dec) for the fullest falls; mornings to beat heat","how":"Central-south interior; scooter or Grab, ~25-30 min from Chaweng","cost":"Free","time":"Half day"}],"weather":{"hazard":"Best months mid-Dec to early Mar (driest, clearest); Jan-Apr generally good and hottest in Apr-May. Wettest is the NE-monsoon Oct-Dec, peaking in Nov (~315mm) when seas get rough and marine tours pause. Humidity is high year-round; no typhoon belt but heavy tropical downpours and occasional flooding in Nov.","months":[{"m":"Jan","hi":29,"lo":26,"rain":58},{"m":"Feb","hi":31,"lo":26,"rain":36},{"m":"Mar","hi":32,"lo":27,"rain":56},{"m":"Apr","hi":32,"lo":27,"rain":76},{"m":"May","hi":33,"lo":27,"rain":132},{"m":"Jun","hi":32,"lo":27,"rain":132},{"m":"Jul","hi":32,"lo":27,"rain":127},{"m":"Aug","hi":32,"lo":27,"rain":127},{"m":"Sep","hi":31,"lo":27,"rain":157},{"m":"Oct","hi":31,"lo":26,"rain":234},{"m":"Nov","hi":30,"lo":26,"rain":315},{"m":"Dec","hi":29,"lo":26,"rain":173}]}}'::jsonb),
  ('Vietnam', 'Hoi An', 'SE', 'Southeast Asia', 15.8801, 108.338, 48, 38, 450, '{"costs":{"allInDayMid":[35,65],"accomPerNight":{"budget":16,"mid":38,"nice":85},"rentMonthly":450,"dailyLiving":{"low":25,"mid":48,"high":80}},"food":"Banh mi from a cart ~$0.80-1.20; bowl of cao lau or pho ~$1.50-2.50; casual local lunch for 2 ~$8-12; mid-range Western/Vietnamese dinner for 2 ~$25-40; local beer (Bia Larue/Saigon) ~$0.80-1.50; cafe coffee (ca phe sua da) ~$1-2, Western espresso ~$2-3.","transport":"Town is flat and walkable/cyclable; hotels lend bikes free or rent ~$1-2/day. Motorbike rental ~$5-7/day or ~$50-70/month. Grab/Xanh SM ride-hail widely used: GrabBike short hops ~$0.60-2, GrabCar across town or to Da Nang airport (~30km) ~$12-16. Local taxis metered but Grab usually cheaper.","internet":"Local SIM/eSIM (Viettel/Mobifone) unlimited data ~$3-8/month; tourist eSIMs (Airalo/Saily) ~$5-15. Cafe and apartment fiber WiFi is fast and reliable (50-100+ Mbps common). Coworking spaces like Hub Hoi An / Sun Tan run ~$5-8/day or ~$80-120/month; many nomads just work from cafes.","landmarks":[{"name":"Hoi An Ancient Town (UNESCO)","why":"Lantern-lit 15th-19th century trading port; Japanese Covered Bridge, old merchant houses, riverside lanterns at night","when":"Late afternoon into evening; magical on the monthly full-moon Lantern Festival","how":"Walk or cycle from anywhere central","cost":"Town entry ticket ~$5 (120,000 VND) covers 5 heritage sites","time":"Half to full day"},{"name":"An Bang Beach","why":"Long sandy beach with relaxed beach bars and seafood shacks, popular with nomads","when":"Dry season Feb-Aug; mornings to avoid midday heat","how":"10-15 min by bike or ~$2-3 GrabBike from Old Town","cost":"Free; sunbed+drink ~$2-4","time":"Half day"},{"name":"My Son Sanctuary","why":"UNESCO Hindu Cham temple ruins (4th-13th c.) set in a jungle valley","when":"Early morning to beat heat and crowds","how":"~40km west; tour ~$15-20 or private car ~$30-40 round trip","cost":"Entry ~$6 (150,000 VND)","time":"Half day"},{"name":"Tra Que Vegetable Village & rice paddies","why":"Cycle through organic herb gardens and emerald rice fields; cooking classes and farm visits","when":"Sunrise or late afternoon","how":"Easy 4km bike ride from town","cost":"Free to cycle; cooking class ~$25-35","time":"2-4 hours"}],"weather":{"hazard":"Best months Feb-May (warm, dry, low rain). Oct-Nov is the wettest with peak monsoon and frequent flooding of the Old Town; Sep-Dec brings typhoon/storm risk off the East Sea. Jun-Aug is hot and humid but mostly dry.","months":[{"m":"Jan","hi":25,"lo":19,"rain":96},{"m":"Feb","hi":26,"lo":20,"rain":32},{"m":"Mar","hi":28,"lo":22,"rain":40},{"m":"Apr","hi":30,"lo":24,"rain":47},{"m":"May","hi":33,"lo":25,"rain":75},{"m":"Jun","hi":34,"lo":26,"rain":88},{"m":"Jul","hi":34,"lo":26,"rain":90},{"m":"Aug","hi":33,"lo":26,"rain":117},{"m":"Sep","hi":31,"lo":24,"rain":297},{"m":"Oct","hi":29,"lo":23,"rain":526},{"m":"Nov","hi":27,"lo":22,"rain":454},{"m":"Dec","hi":25,"lo":20,"rain":209}]}}'::jsonb),
  ('Vietnam', 'Nha Trang', 'SE', 'Southeast Asia', 12.2388, 109.1967, 50, 35, 380, '{"costs":{"allInDayMid":[40,75],"accomPerNight":{"budget":16,"mid":35,"nice":75},"rentMonthly":380,"dailyLiving":{"low":28,"mid":50,"high":90}},"food":"Bun cha or banh mi street meal $1.50-3; casual local dinner for 2 ~$10-14; mid-range 3-course dinner for 2 ~$21; fresh-seafood splurge for 2 $30-45. Draught beer $0.60-1, bottled craft $2; cappuccino $1.75, Vietnamese iced coffee (ca phe sua da) $0.80-1.20.","transport":"Walkable beachfront core. Grab bike $1-2 short hop, Grab car $2-4 across town; rented scooter $5-7/day or ~$50/month plus cheap petrol. Airport (CXR, ~35km south) by Grab car ~$15-18 or shared shuttle bus ~$2-3. No metro; taxis (Mai Linh/Vinasun) metered.","internet":"Home fiber 60+ Mbps ~$9/month; mobile data is fast and cheap (Viettel/Mobifone tourist eSIM ~$5-8 for 30 days with generous data). Coworking is limited but present (e.g. iGo, Maac, cafe coworking) ~$70-100/month for a hot desk; many cafes have reliable free wifi.","landmarks":[{"name":"Po Nagar Cham Towers","why":"8th-13th century Cham Hindu temple complex on a hill over the Cai River, Nha Trang''s top cultural site","when":"Early morning 8-9am to beat heat and crowds","how":"Grab bike/car ~$2 from center (3km north), or scooter","cost":"25,000 VND (~$1) entry","time":"1-1.5 hours"},{"name":"VinWonders & Vinpearl Cable Car (Hon Tre Island)","why":"Large theme/water park reached by a scenic over-sea cable car; full day of rides and beaches","when":"Weekday to avoid crowds; arrive at opening","how":"Cable car or speedboat from the dedicated terminal south of town","cost":"~1,050,000 VND (~$41) full-day ticket; ~$27 after 4pm","time":"Half to full day"},{"name":"Island-hopping & scuba/snorkel trip","why":"Nha Trang is Vietnam''s diving capital; clear bay waters, coral, and beach islands (Hon Mun marine park)","when":"Feb-Aug for calm seas and best visibility","how":"Boat tours depart Cau Da pier; book via dive shops or hotel","cost":"Group boat tour ~$15-25pp; 2 fun dives ~$60-70pp","time":"Full day"},{"name":"Long Son Pagoda & White Buddha","why":"Hilltop temple crowned by a giant seated white Buddha with panoramic city views","when":"Late afternoon for cooler light and views","how":"Grab/scooter ~$1-2 from center, then short stair climb","cost":"Free (small donation)","time":"45-60 min"}],"weather":{"hazard":"Best months Feb-Aug (dry, sunny, calm sea). Oct-Nov is peak rainy season with the wettest months (300-330mm) and flood/storm risk; Sep-Dec is the NE monsoon with occasional typhoons/tropical depressions hitting the central coast. Hot and muggy May-Aug; Jan-Feb is the coolest and driest.","months":[{"m":"Jan","hi":27.2,"lo":21.7,"rain":40},{"m":"Feb","hi":28,"lo":22,"rain":15},{"m":"Mar","hi":29.4,"lo":23.3,"rain":30},{"m":"Apr","hi":31.1,"lo":25,"rain":35},{"m":"May","hi":32.4,"lo":25.8,"rain":70},{"m":"Jun","hi":32.7,"lo":26.1,"rain":60},{"m":"Jul","hi":32.5,"lo":25.9,"rain":35},{"m":"Aug","hi":32.7,"lo":25.9,"rain":50},{"m":"Sep","hi":31.8,"lo":25.2,"rain":160},{"m":"Oct","hi":30,"lo":24.4,"rain":300},{"m":"Nov","hi":28.6,"lo":23.6,"rain":330},{"m":"Dec","hi":27.3,"lo":22.6,"rain":155}]}}'::jsonb),
  ('Indonesia', 'Yogyakarta', 'SE', 'Southeast Asia', -7.7956, 110.3695, 50, 30, 320, '{"costs":{"allInDayMid":[35,70],"accomPerNight":{"budget":14,"mid":30,"nice":65},"rentMonthly":320,"dailyLiving":{"low":25,"mid":50,"high":85}},"food":"Street nasi goreng or gudeg 15,000-25,000 IDR ($1-1.60); casual sit-down meal for 2 ~$8-12; mid-range dinner for 2 at a nicer warung/restaurant ~$20-30; large Bintang beer ~$2.50-3.50; local coffee/kopi ~$1, cafe latte ~$2-2.50.","transport":"Gojek/Grab dominate: motorbike taxi ~$0.70-1.50 across town, car ~$2-4. Rent a scooter ~$4-5/day or ~$60/month. TransJogja bus ~$0.25/ride. Becak (pedicab) short hops $1-2 after haggling. Most rides in the compact center are very cheap.","internet":"Tourist eSIM (Telkomsel/Holafly type) ~$7 for 5GB/week, ~$15 for 20GB; local Telkomsel SIM ~$5-10/month. Fiber in apartments is common and fast. Coworking widely available: day pass ~$3-6, monthly hot desk ~$60-100; cafes with free wifi everywhere.","landmarks":[{"name":"Borobudur Temple","why":"World''s largest Buddhist temple, a 9th-century UNESCO masterpiece of stone reliefs and stupas; iconic sunrise views over volcanoes and jungle.","when":"Early morning (sunrise) to beat heat and crowds; dry season May-Sep best.","how":"About 1 hr drive NW; Grab/car ~$20-30 round trip, or organized tour ~$25-40 pp.","cost":"Foreigner entry ~$25 (temple grounds); climbing the temple structure timed-slot ~$30 extra.","time":"Half day"},{"name":"Prambanan Temple","why":"Towering 9th-century Hindu temple complex (UNESCO) with dramatic spires dedicated to Shiva; stunning at sunset and for the Ramayana ballet.","when":"Late afternoon for sunset light; combine with evening Ramayana dance show.","how":"~17 km east; Grab/car ~$5-8 each way or TransJogja bus.","cost":"Foreigner entry ~$25; Ramayana ballet ~$10-30.","time":"Half day"},{"name":"Kraton (Sultan''s Palace) & Taman Sari","why":"Living royal palace of the Yogyakarta Sultanate plus the atmospheric Water Castle ruins; the cultural heart of the city.","when":"Morning, when gamelan/dance performances are often held and before midday heat.","how":"Central, walkable or short Grab ride from most accommodation.","cost":"Each site ~$1-3 entry, plus small camera fee.","time":"2-3 hours"},{"name":"Malioboro Street & Beringharjo Market","why":"The bustling main shopping and street-food artery; batik, souvenirs, and Jogja''s famous nightlife of street musicians and lesehan dining.","when":"Late afternoon into evening when it comes alive and cools down.","how":"Central; walkable, becak, or Grab.","cost":"Free to stroll; budget for street food and shopping.","time":"2-3 hours"}],"weather":{"hazard":"Best months Jun-Sep (dry season, low rain, comfortable). Wet/monsoon season Nov-Apr peaks Jan-Mar with heavy afternoon downpours and high humidity. No typhoons (near equator). Year-round heat 30-32C; volcanic ash possible during Mt Merapi activity.","months":[{"m":"Jan","hi":31,"lo":22,"rain":375},{"m":"Feb","hi":31,"lo":22,"rain":314},{"m":"Mar","hi":31,"lo":22,"rain":363},{"m":"Apr","hi":32,"lo":22,"rain":179},{"m":"May","hi":32,"lo":22,"rain":142},{"m":"Jun","hi":31,"lo":21,"rain":61},{"m":"Jul","hi":31,"lo":20,"rain":32},{"m":"Aug","hi":32,"lo":20,"rain":24},{"m":"Sep","hi":32,"lo":21,"rain":52},{"m":"Oct","hi":32,"lo":22,"rain":136},{"m":"Nov","hi":31,"lo":22,"rain":219},{"m":"Dec","hi":31,"lo":22,"rain":284}]}}'::jsonb),
  ('Philippines', 'Cebu', 'SE', 'Southeast Asia', 10.3157, 123.8854, 55, 45, 480, '{"costs":{"allInDayMid":[45,80],"accomPerNight":{"budget":22,"mid":45,"nice":95},"rentMonthly":480,"dailyLiving":{"low":30,"mid":55,"high":95}},"food":"Local carinderia meal ~$2.50-4; casual sit-down dinner for two ~$15-22; mid-range restaurant dinner for two ~$30-45; local beer (San Miguel) ~$1.30-2; coffee at a cafe ~$2.50-3.50. Lechon (roast pork) is the Cebu specialty.","transport":"Jeepneys ~$0.25 min fare (PHP 14), modern jeepneys ~$0.30. Grab is the go-to ride-hail: short city hop ~$2.50-4, cross-town ~$5-8, airport (Mactan) to city ~$6-11. MyBus airport shuttle to SM ~$1-2. Traffic is heavy at peak hours; motorbike-style habal-habal exists but Grab is safer for nomads.","internet":"Home fiber ~$25-40/mo (PLDT/Converge/Globe). Tourist eSIM (Airalo/local Globe-Smart) ~$5-15 for 5-20GB. Coworking is solid in IT Park and Cebu Business Park: day pass ~$8-15, monthly hot desk ~$100-150 (The Tide, Ete Co., Company spaces). Mall and cafe wifi widely available.","landmarks":[{"name":"Magellan''s Cross & Basilica del Santo Niño","why":"Cebu''s historic-religious heart: the 1521 cross marking the arrival of Christianity in the Philippines, beside the country''s oldest church and the revered Santo Niño icon.","when":"Year-round; mornings to avoid heat and crowds. January for the Sinulog festival.","how":"Central downtown Cebu; short Grab ride (~$2-3) or jeepney from most areas.","cost":"Free (donations welcome)","time":"1-1.5 hours"},{"name":"Kawasan Falls (Badian)","why":"Iconic turquoise multi-tier waterfalls and the launch point for the famous canyoneering adventure through Matutinao River.","when":"Dry season Jan-May for best water clarity; go early to beat day-trip crowds.","how":"~3 hours south by car/bus; most do an organized canyoneering day tour from Cebu City.","cost":"Entrance ~$1.50; canyoneering tour ~$30-55 pp incl. gear/guide","time":"Full day"},{"name":"Oslob whale shark watching & Moalboal","why":"Swim alongside whale sharks at Oslob and snorkel the famous sardine run and turtles at Moalboal''s Panagsama reef.","when":"Whale sharks year-round (early morning best); sardine run reliable most of the year.","how":"South coast, ~3 hours by bus/van; combine as a 1-2 day trip from the city.","cost":"Whale shark watch+snorkel ~$18-30; sardine run snorkel ~$5-10","time":"Full day to overnight"},{"name":"Temple of Leah & Sirao Garden (Busay hills)","why":"A grand Roman-style hilltop temple with city views, paired with the colorful ''Little Amsterdam'' celosia flower garden in the cool uplands.","when":"Late afternoon for cooler air and sunset over Cebu City.","how":"Busay/Transcentral Highway above the city; ~30-45 min Grab (~$8-12 round trip with wait).","cost":"Temple ~$1.50; garden ~$1.50","time":"Half day"}],"weather":{"hazard":"Best months: Feb-May (driest, sunny). Wettest June-November with peak rain around July-October; typhoon risk runs roughly June-December though Cebu is somewhat sheltered versus Luzon. Hot and humid year-round (highs 30-33C); March-May is the hottest stretch.","months":[{"m":"Jan","hi":30,"lo":24,"rain":110},{"m":"Feb","hi":30,"lo":24,"rain":65},{"m":"Mar","hi":31,"lo":24,"rain":50},{"m":"Apr","hi":32,"lo":25,"rain":55},{"m":"May","hi":33,"lo":26,"rain":110},{"m":"Jun","hi":32,"lo":25,"rain":165},{"m":"Jul","hi":32,"lo":25,"rain":180},{"m":"Aug","hi":32,"lo":25,"rain":145},{"m":"Sep","hi":32,"lo":25,"rain":165},{"m":"Oct","hi":32,"lo":25,"rain":195},{"m":"Nov","hi":31,"lo":25,"rain":155},{"m":"Dec","hi":31,"lo":24,"rain":130}]}}'::jsonb),
  ('Philippines', 'El Nido', 'SE', 'Southeast Asia', 11.1801, 119.392, 95, 55, 700, '{"costs":{"allInDayMid":[80,150],"accomPerNight":{"budget":22,"mid":55,"nice":130},"rentMonthly":700,"dailyLiving":{"low":50,"mid":95,"high":165}},"food":"Local silog/carinderia meal ~$3-5; casual dinner for 2 (grilled fish, rice, veg) ~$14-20; mid beachfront/Western dinner for 2 ~$35-50; San Miguel beer ~$2; coffee ~$2.50-3.50. Tourist-strip prices run notably higher than mainland Philippines.","transport":"Tricycles dominate: town to Corong-Corong ~PHP 50-100 ($1-2), short hops ~PHP 15-20pp shared. No Grab/ride-hail in El Nido; negotiate or use hotel transfers. Shared van Puerto Princesa-El Nido (5-6h) ~PHP 700 ($12)pp. Motorbike rental ~PHP 500-700/day ($9-12).","internet":"Globe is the usable network (~10-20 Mbps LTE); Smart is weak. Tourist eSIMs (Airalo/Holafly) ~$5-10 for a few GB. WiFi is patchy and slow town-wide; Lio Beach and Corong-Corong have better fiber. Coworking: Lexias El Nido and Neighbors & Nomads offer reliable work-grade WiFi (~PHP 300-500/day).","landmarks":[{"name":"Big Lagoon & Small Lagoon (Bacuit Bay)","why":"El Nido''s signature karst-cliff lagoons with turquoise water, kayaking, and snorkeling - the reason most people come.","when":"Dec-May dry season, early morning to beat crowds and afternoon wind.","how":"Tour A island-hopping boat from El Nido town beach; kayak rental extra inside Big Lagoon.","cost":"Tour A ~PHP 1,400-1,600 ($25-29)pp incl lunch; +PHP 200 ($3.50) kayak","time":"Full day (approx 9am-4pm)"},{"name":"Nacpan Beach","why":"Long, uncrowded twin golden-sand beach with a viewpoint - the best mainland beach near town.","when":"Year-round, best on dry-season afternoons; great for sunset.","how":"Tricycle or van from town (~45 min), or rent a motorbike.","cost":"Tricycle round trip ~PHP 800-1,200 ($14-21) for 2; small entrance/parking fee","time":"Half to full day"},{"name":"Las Cabanas Beach & zipline","why":"Closest swimmable sunset beach to town with beach bars and an island-to-beach zipline.","when":"Late afternoon for sunset, dry season.","how":"Tricycle from town center (~10-15 min).","cost":"Tricycle ~PHP 150 ($2.70); zipline ~PHP 550 ($10)pp","time":"2-4 hours"},{"name":"Taraw Cliff Canopy Walk / viewpoint","why":"Via ferrata climb up the limestone cliff over El Nido town for panoramic Bacuit Bay views.","when":"Dry season, early morning (cooler, clearer).","how":"Guided via ferrata booked in town; harness and guide provided.","cost":"~PHP 600-1,000 ($11-18)pp","time":"1.5-2 hours"}],"weather":{"hazard":"Best months Dec-Apr (dry, calm seas, reliable island-hopping). May is hot and transitional. Jun-Oct is the SW monsoon (habagat) with heavy rain, peaking Jul-Sep; tours and boats are frequently cancelled. Typhoons can affect the region mainly Aug-Nov, though Palawan is hit less often than the rest of the Philippines.","months":[{"m":"Jan","hi":30,"lo":24,"rain":12},{"m":"Feb","hi":31,"lo":24,"rain":5},{"m":"Mar","hi":32,"lo":25,"rain":25},{"m":"Apr","hi":33,"lo":26,"rain":45},{"m":"May","hi":32,"lo":26,"rain":159},{"m":"Jun","hi":31,"lo":25,"rain":333},{"m":"Jul","hi":30,"lo":25,"rain":400},{"m":"Aug","hi":30,"lo":25,"rain":433},{"m":"Sep","hi":30,"lo":25,"rain":349},{"m":"Oct","hi":31,"lo":25,"rain":264},{"m":"Nov","hi":31,"lo":25,"rain":146},{"m":"Dec","hi":30,"lo":24,"rain":60}]}}'::jsonb)
on conflict (country, city) do update set
  region=excluded.region, region_name=excluded.region_name, lat=excluded.lat, lng=excluded.lng,
  daily_living_mid=excluded.daily_living_mid, accom_mid=excluded.accom_mid,
  rent_monthly=excluded.rent_monthly, attributes=excluded.attributes, updated_at=now();

